using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Configuration;
using Microsoft.Agents.AI.ChatCompletion;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);
builder.Configuration.AddEnvironmentVariables();

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

builder.Services.AddSingleton<Notebook>();
builder.Services.AddSingleton<ResearchTools>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "You are a research assistant. Given a topic, use the web_search tool to find "
    + "information from multiple angles, then use the add_note tool to record key findings. "
    + "After gathering enough information, use the get_notes tool to review your notes and "
    + "provide a comprehensive summary. Always search at least 3 different queries before summarizing.");

var chatOptions = new ChatOptions
{
    Temperature = 0.2f,
    MaxOutputTokens = 2048,
    Tools = [AIFunctionFactory.Create(researchTools.WebSearch),
             AIFunctionFactory.Create(researchTools.AddNote),
             AIFunctionFactory.Create(researchTools.GetNotes)],
};

var invokeOptions = new AgentInvokeOptions
{
    MaximumIterations = 15,
    ModelOptions = chatOptions,
};

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    researchTools.Notebook.Clear();

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
    };

    Console.WriteLine("\nResearching...\n");

    try
    {
        await foreach (var message in agent.InvokeStreamingAsync(history, invokeOptions))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
            {
                Console.Write(message.Text);
            }
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine("\n");
}

