namespace ResearchAgent;

/// <summary>
/// Simple in-memory note store for the research agent.
/// </summary>
public sealed class Notebook
{
    private readonly List<NoteEntry> _notes = [];

    public void Add(string title, string content)
    {
        _notes.Add(new NoteEntry(title, content, DateTime.UtcNow));
    }

    public IReadOnlyList<NoteEntry> GetAll() => _notes.AsReadOnly();

    public void Clear() => _notes.Clear();
}

public sealed record NoteEntry(string Title, string Content, DateTime Timestamp);

using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace ResearchAgent;

/// <summary>
/// Tools exposed to the research agent for web search and note-taking.
/// </summary>
public sealed class ResearchTools
{
    private static readonly HttpClient HttpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    public Notebook Notebook { get; }

    public ResearchTools(Notebook notebook)
    {
        Notebook = notebook;
    }

    [Description("Search the web for information on a query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> WebSearch(
        [Description("The search query string")] string query)
    {
        try
        {
            // Use DuckDuckGo Instant Answer API (no API key required)
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await HttpClient.GetFromJsonAsync<DuckDuckGoResponse>(url);

            var results = new List<SearchResult>();

            if (!string.IsNullOrWhiteSpace(response?.Abstract))
            {
                results.Add(new SearchResult(
                    response.Heading ?? "Main Result",
                    response.Abstract,
                    response.AbstractURL ?? ""));
            }

            if (response?.RelatedTopics is not null)
            {
                foreach (var topic in response.RelatedTopics.Take(5))
                {
                    if (!string.IsNullOrWhiteSpace(topic.Text))
                    {
                        results.Add(new SearchResult(
                            topic.Text[..Math.Min(80, topic.Text.Length)],
                            topic.Text,
                            topic.FirstURL ?? ""));
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing your search.";
            }

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: \"{query}\"");
            sb.AppendLine();
            for (var i = 0; i < results.Count; i++)
            {
                sb.AppendLine($"[{i + 1}] {results[i].Title}");
                sb.AppendLine($"    {results[i].Snippet}");
                if (!string.IsNullOrEmpty(results[i].Url))
                    sb.AppendLine($"    URL: {results[i].Url}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}. Try a different query.";
        }
    }

    [Description("Add a research note with a title and content. Use this to record key findings during research.")]
    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string content)
    {
        Notebook.Add(title, content);
        return $"Note added: \"{title}\" ({Notebook.GetAll().Count} total notes)";
    }

    [Description("Retrieve all research notes taken so far. Use this to review findings before writing a summary.")]
    public string GetNotes()
    {
        var notes = Notebook.GetAll();
        if (notes.Count == 0)
            return "No notes have been taken yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({notes.Count} total) ===");
        sb.AppendLine();

        for (var i = 0; i < notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {notes[i].Title} ---");
            sb.AppendLine(notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private sealed record SearchResult(string Title, string Snippet, string Url);
}

