using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Configuration;
using Microsoft.Agents.AI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);
builder.Configuration.AddEnvironmentVariables();

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

builder.Services.AddSingleton<Notebook>();
builder.Services.AddSingleton<ResearchTools>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.WebSearch),
    AIFunctionFactory.Create(researchTools.AddNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: "You are a research assistant. Given a topic, use the WebSearch tool to find "
        + "information from multiple angles, then use the AddNote tool to record key findings. "
        + "After gathering enough information, use the GetNotes tool to review your notes and "
        + "provide a comprehensive summary. Always search at least 3 different queries before summarizing.",
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking tools.",
    tools: tools);

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0.2f,
        MaxOutputTokens = 2048,
    },
};

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    researchTools.Notebook.Clear();

    Console.WriteLine("\nResearching...\n");

    try
    {
        var session = await agent.CreateSessionAsync(
            conversationId: Guid.NewGuid().ToString());

        var prompt = $"Research the following topic and provide a comprehensive summary: {topic}";

        await foreach (var update in agent.RunStreamingAsync(prompt, session, runOptions))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine("\n");
}

